<template><div class="page"><header class="page-head"><div><h1>Notifications</h1><p>Historique des envois et file de distribution.</p></div><button class="icon-button" :disabled="loading" title="Actualiser" @click="load"><RefreshCw :class="{spin:loading}"/></button></header><div class="segmented page-tabs"><button :class="{active:tab==='history'}" @click="tab='history';offset=0;load()">Historique</button><button :class="{active:tab==='pending'}" @click="tab='pending';offset=0;load()">En attente <span v-if="pendingTotal" class="badge">{{ pendingTotal }}</span></button></div><div class="toolbar wrap"><input v-model="search" class="search" type="search" placeholder="Media, destinataire ou evenement"><select v-if="tab==='history'" v-model="state"><option value="">Tous les etats</option><option value="success">Envoyees</option><option value="error">Erreurs</option></select><select v-if="tab==='history'" v-model="eventType"><option value="">Tous les types</option><option value="request">Demandes</option><option value="available">Disponibilites</option><option value="system">Erreurs systeme</option></select><div v-if="tab==='pending'&&rows.length" class="actions"><button class="secondary" @click="purge(true)"><CheckCheck/>Purger et marquer traitees</button><button class="secondary danger" @click="purge(false)"><Trash2/>Purger</button></div></div><p v-if="error" class="notice error-text">{{ error }}</p><section class="panel table-wrap"><table><thead><tr><th><input v-if="tab==='pending'" type="checkbox" :checked="allSelected" @change="toggleAll"></th><th>Date</th><th>Evenement</th><th>Media</th><th>Destinataires</th><th>Etat</th><th></th></tr></thead><tbody><tr v-for="row in rows" :key="row.id"><td><input v-if="tab==='pending'" v-model="selected" type="checkbox" :value="row.id"></td><td>{{ formatDate(row.sent_at||row.created_at) }}</td><td><strong>{{ row.event_label||row.event }}</strong><small class="table-detail">{{ context(row) }}</small></td><td>{{ row.media_title||'-' }}</td><td>{{ row.recipient||(row.recipients||[]).join(', ')||'-' }}</td><td><span class="badge" :class="row.success===false||row.valid===false?'failed':tab==='pending'?'pending':'available'">{{ row.success===false?'Erreur':row.valid===false?'Invalide':tab==='pending'?'En attente':'Envoyee' }}</span><small v-if="row.error_msg" class="table-detail error-text">{{ row.error_msg }}</small></td><td><button v-if="tab==='history'&&!row.success" class="icon-button" title="Renvoyer" @click="resend(row)"><Send/></button></td></tr></tbody></table><p v-if="!loading&&!rows.length" class="empty">Aucune notification.</p></section><div v-if="tab==='history'&&total>limit" class="pagination"><button class="secondary" :disabled="offset===0" @click="page(-1)"><ChevronLeft/>Precedent</button><span>{{ offset+1 }}-{{ Math.min(offset+limit,total) }} sur {{ total }}</span><button class="secondary" :disabled="offset+limit>=total" @click="page(1)">Suivant<ChevronRight/></button></div></div></template>
<script setup>import { computed,onMounted,ref,watch } from 'vue';import { CheckCheck,ChevronLeft,ChevronRight,RefreshCw,Send,Trash2 } from '@lucide/vue';import { api } from '@/api';import { useRealtime } from '@/events';const rows=ref([]),tab=ref('history'),loading=ref(false),error=ref(''),search=ref(''),state=ref(''),eventType=ref(''),selected=ref([]),total=ref(0),pendingTotal=ref(0),offset=ref(0);const limit=50;const allSelected=computed(()=>rows.value.length&&rows.value.every(x=>selected.value.includes(x.id)));function formatDate(v){return v?new Intl.DateTimeFormat('fr-FR',{dateStyle:'short',timeStyle:'short'}).format(new Date(v)):'-'}function context(row){const c=row.context||{};return [c.scope,c.language,c.is_upgrade?'amelioration':''].filter(Boolean).join(' - ')||row.event_description||''}async function load(){loading.value=true;error.value='';try{const q=new URLSearchParams({limit,offset:offset.value});if(state.value)q.append('state',state.value);if(eventType.value)q.append('eventType',eventType.value);if(search.value)q.append('search',search.value);const data=tab.value==='history'?await api(`/api/notifications/log?${q.toString()}`):await api('/api/notifications/pending');rows.value=data.items||[];total.value=data.total||0;if(tab.value==='pending')pendingTotal.value=data.total||0;else api('/api/notifications/pending').then(x=>pendingTotal.value=x.total).catch(()=>{})}catch(e){error.value=e.message}finally{loading.value=false}}async function resend(row){await api(`/api/notifications/${row.id}/resend`,{method:'POST'});await load()}async function purge(markHandled){const ids=selected.value;if(!confirm(`Purger ${ids.length?ids.length:'toute la file'} notification(s) ?`))return;await api('/api/notifications/pending/purge',{method:'POST',body:JSON.stringify({ids,mark_handled:markHandled})});selected.value=[];await load()}function toggleAll(e){selected.value=e.target.checked?rows.value.map(x=>x.id):[]}function page(delta){offset.value=Math.max(0,offset.value+delta*limit);load()}watch([state,eventType],()=>{offset.value=0;load()});let searchTimeout;watch(search,()=>{clearTimeout(searchTimeout);searchTimeout=setTimeout(()=>{offset.value=0;load()},300)});useRealtime(['notification.updated'],load);onMounted(load);</script>
